import org.owasp.encoder.Encode;

import java.io.FileWriter;
import java.io.IOException;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly handling user input by encoding it before outputting to HTML
        String output = "<html><body><p>User Input: " + Encode.forHtml(userInput) + "</p></body></html>";

        try {
            FileWriter fileWriter = new FileWriter("output.html");
            fileWriter.write(output);
            fileWriter.close();
            System.out.println("Output written to output.html");
        } catch (IOException e) {
            System.out.println("Error writing output: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
